select
to_char(id) as id, to_char(team) as team, to_char(calcPeriod) as calcPeriod, to_char(costSum) as costSum, to_char(priceSum) as priceSum, to_char(remark) as remark, to_char(pm) as pm, to_char(id) as id, to_char(requireOperatorCost) as requireOperatorCost, to_char(requireOperatorPrice) as requireOperatorPrice, to_char(bugOperatorCost) as bugOperatorCost, to_char(bugOperatorPrice) as bugOperatorPrice, to_char(maintanceOperatorCost) as maintanceOperatorCost, to_char(maintanceOperatorPrice) as maintanceOperatorPrice, to_char(otherOperatorCost) as otherOperatorCost, to_char(otherOperatorPrice) as otherOperatorPrice
from vm_cap_require_main where calcPeriod = #calcMonth# and team = util_common.getEnumIdByShow(1822868929259851192,#team#)
